revision.text:
{{Documentation subpage}}
<!-- Categories and interwikis go at the bottom of this page. -->

This template is a wrapper for {{Tlx|Cleanup}}

==Usage==
{{Tlc|Cleanup section|date{{=}}{{CURRENTMONTHNAME}} {{CURRENTYEAR}}|reason{{=}}}}

To be placed in sections that need attention. Full instructions are given at {{Tlx|Cleanup}}.

To show it compressed at the left side of the section, add the parameter <code>small=left</code>.
<includeonly>{{Sandbox other||
<!-- Categories and interwikis go here: -->
[[Category:Wikipedia section templates]]
[[Category:Cleanup templates]]
}}</includeonly>
===TemplateData===
{{TemplateData header}}
<templatedata>
{
	"params": {
		"reason": {
			"label": "Reason",
			"type": "string",
			"required": true,
			"description": "Reason for requesting cleanup",
			"example": "The article is full of incorrect capitalization."
		},
		"date": {
			"label": "Month and year",
			"suggested": true,
			"description": "The month and year that the template was placed (in full).",
			"example": "January 2013",
			"type": "line",
			"autovalue": "May 2025"
		},
		"small": {
			"label": "Make template small",
			"description": "Enter \"left\" here to make the template box small and aligned to the left.",
			"type": "string",
			"autovalue": "left"
		},
		"talksection": {
			"label": "Talk page section",
			"description": "The section of the talk page explaining what needs to be done",
			"type": "string"
		},
		"nocat": {
			"label": "No category",
			"description": "Suppress categorization",
			"type": "string"
		},
		"demospace": {}
	},
	"description": "This tag is intended to identify pages that need wikification or the correction of spelling, grammar, typographical errors, tone, and other similar, non-content-focused changes. Use this tag when the article needs improvement per WP:BETTER.",
	"format": "inline"
}
</templatedata>

